1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
12	
13	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
14	
15	const quotePremium = (step: QuoteStep): number => {
16	  const itemsBase = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
17	  return itemsBase + PROCESSING_FEE;
18	};
19	
20	export const runScenario = (input: unknown): unknown => {
21	  const scenario = input as Scenario;
22	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
23	  return { results };
24	};
